package problems;

import java.util.Arrays;
import java.util.HashSet;
import java.util.List;
import java.util.Map;
import java.util.Set;
import java.util.function.Function;
import java.util.stream.Collector;
import java.util.stream.Collectors;

public class Duplicate {

    public static void main(String[] args) {

        int[] nums = {1, 2, 3, 3};

        System.out.println("Contains Duplicate element " + containsDuplicate(nums));
        System.out.println("Contains Duplicate element within window " + containsDuplicateInWindow(nums, 2));
        System.out.println("Duplicate Elements are " + listOfDuplicates(nums));

    }

    public static boolean containsDuplicate(int[] nums) {
        // Given an integer array nums, return true if any value appears at least twice in the array, and return false if every element is distinct
        // Example 1:
        // Input: nums = [1,2,3,1)
        // Output: true
        // Example 2:
        // Input: nums = [1,2,3,4]
        // Output: false
        // Example 3:
        // Input: nums = [1,1,1,3,3,4,3,2,4,2)
        // Output: true
        Set<Integer> seen = new HashSet<>();
        for (int num : nums) {
            if (!seen.add(num)) {
                return true;
            }
        }
        return false;
    }



    public static boolean containsDuplicateInWindow(int[] nums,int window){
        // Given an integer array nums and an integer k, return true if there are two distinct indices i and j in the array such that nums[i] == nums[j] and abs(i - j) <= k.
        // Example 1:
        // Input: nums = [1,2,3,1], k = 3
        // output: true
        // Example 2:
        // Input: nums = [1,0,1,1], k = 1
        // Output: true
        // Example 3:
        // Input: nums = [1,2,3,1,2,3], k = 2
        // Output: false

        Set<Integer> set = new HashSet<>();

        for(int i=0;i<nums.length;i++){
            if(set.contains(nums[i])) return true;

            set.add(nums[i]);
            if(set.size() > window){
                set.remove(nums[i-window]);
            }
        }
        return false;
    }

    public static List<Integer> listOfDuplicates(int[] nums) {

        // Given an interger array nums, return the duplicate elements as list

        return Arrays.stream(nums).boxed().collect(Collectors.toList())
                .stream().collect(Collectors.groupingBy(Function.identity(), Collectors.counting()))
                .entrySet().stream().filter(entry -> entry.getValue() > 1)
                .map(Map.Entry::getKey).collect(Collectors.toList());
    }

}
